<script setup lang="ts">
import { computed, onMounted, ref } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import { Check, CopyDocument, Download, Printer, Refresh, Warning } from '@element-plus/icons-vue'
import { ElMessage } from 'element-plus'
import { usePlatformStore } from '../stores/platform'

const platform=usePlatformStore()
const route=useRoute(),router=useRouter()
const active=ref(0),language=ref<'en'|'zh'>('en'),loading=ref(false)
const groups=ref<Array<{id:string;label:string}>>([])
const locations=ref<Array<{id:string;label:string}>>([])
const structureDialog=ref(false),structureMode=ref<'location'|'group'>('group')
const structure=ref({locationId:'',code:'',name:''})
const form=ref({name:'',groupId:'',model:'TECNO CAMON 18 Premier',sims:[{slot:0,iccid:'',phone_number:'',account_name:''},{slot:1,iccid:'',phone_number:'',account_name:''}]})
const created=ref<any>(null),qualification=ref<any>(null),checkDialog=ref(false),decisionDialog=ref(false),resumedFromUrl=ref(false)
const selectedCheck=ref<any>(null),checkStatus=ref<'passed'|'failed'>('passed'),evidenceReference=ref(''),evidenceNotes=ref('')
const decision=ref<'approve'|'reject'>('approve'),decisionReason=ref(''),password=ref('')
const code=computed(()=>String(created.value?.activation_code??''));const expires=computed(()=>created.value?.activation_expires_at?new Date(created.value.activation_expires_at).toLocaleTimeString():'—')
const fieldManualUrl=computed(()=>language.value==='en'?'/manuals/telebirr-field-phone-installation-en.pdf':'/manuals/telebirr-field-phone-installation-zh-CN.pdf')
const operatorManualUrl=computed(()=>language.value==='en'?'/manuals/telebirr-phone-installation-en.pdf':'/manuals/telebirr-phone-installation-zh-CN.pdf')
const allPassed=computed(()=>Boolean(qualification.value?.checks?.length)&&qualification.value.checks.every((item:any)=>item.status==='passed'))
const canRegenerate=computed(()=>created.value?.status==='pending')
const enrollmentBlocked=computed(()=>['quarantined','retired'].includes(String(created.value?.status??'')))
async function loadFleetOptions(){if(platform.demoMode)return;const tree=await platform.fleetTree();locations.value=tree.map((location:any)=>({id:location.id,label:location.name}));groups.value=tree.flatMap((location:any)=>location.groups.map((group:any)=>({id:group.id,label:`${location.name} · ${group.name}`})));if(!groups.value.some(item=>item.id===form.value.groupId))form.value.groupId=groups.value[0]?.id??''}
function applyQualification(view:any){qualification.value=view;created.value={...created.value,id:view.device.id,name:view.device.name,status:view.device.status,sims:view.device.sims.map((sim:any)=>({id:sim.id,slot:sim.slot,phone_number:sim.phone_number,account_name:sim.account_name,status:sim.status}))};form.value.name=view.device.name}
function routeDeviceId(){const value=Array.isArray(route.query.device)?route.query.device[0]:route.query.device;return typeof value==='string'&&/^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(value)?value:''}
async function resumeFromRoute(){if(!route.query.device)return;const deviceId=routeDeviceId();if(!deviceId){ElMessage.error('The enrollment link has an invalid device ID');return}if(platform.demoMode){ElMessage.warning('Enrollment resume requires the live server');return}loading.value=true;try{const view=await platform.getQualification(deviceId);applyQualification(view);resumedFromUrl.value=true;if(view.status==='approved')active.value=3;else if(view.device.status==='pending'&&view.status==='pending')active.value=1;else active.value=2;if(['quarantined','retired'].includes(view.device.status))ElMessage.warning('This device must be recovered from Fleet before enrollment can continue')}catch(error){ElMessage.error(error instanceof Error?error.message:'Could not resume enrollment')}finally{loading.value=false}}
onMounted(async()=>{await loadFleetOptions();await resumeFromRoute()})
function openStructure(mode:'location'|'group'){structureMode.value=mode;structure.value={locationId:locations.value[0]?.id??'',code:'',name:''};structureDialog.value=true}
async function saveStructure(){if(!structure.value.code.trim()||!structure.value.name.trim()||(structureMode.value==='group'&&!structure.value.locationId)){ElMessage.warning('Complete the required fleet fields');return}loading.value=true;try{if(structureMode.value==='location')await platform.createLocation({code:structure.value.code.trim(),name:structure.value.name.trim()});else await platform.createGroup({location_id:structure.value.locationId,code:structure.value.code.trim(),name:structure.value.name.trim()});await loadFleetOptions();structureDialog.value=false;ElMessage.success(`${structureMode.value==='location'?'Location':'Group'} created`)}catch(error){ElMessage.error(error instanceof Error?error.message:'Could not create fleet structure')}finally{loading.value=false}}
async function createRecord(){if(platform.demoMode){ElMessage.warning('Enrollment is disabled in demo mode because activation codes must come from the server');return}loading.value=true;try{created.value=await platform.createDevice({group_id:form.value.groupId,name:form.value.name,model:form.value.model,sims:form.value.sims.map(item=>({slot:item.slot,iccid:item.iccid.replace(/\s/g,''),phone_number:item.phone_number,account_name:item.account_name}))});await router.replace({name:'add-phone',query:{device:created.value.id}});active.value=1;ElMessage.success('Server device record and one-time activation code created')}catch(error){ElMessage.error(error instanceof Error?error.message:'Device creation failed')}finally{loading.value=false}}
async function regenerate(){if(!created.value?.id)return;loading.value=true;try{const result=await platform.regenerateActivationCode(created.value.id);created.value={...created.value,...result};ElMessage.success('Previous code invalidated; new server code created')}catch(error){ElMessage.error(error instanceof Error?error.message:'Could not regenerate code')}finally{loading.value=false}}
function copy(){navigator.clipboard?.writeText(code.value);ElMessage.success('Activation code copied')}
async function loadQualification(){if(!created.value?.id)return;loading.value=true;try{applyQualification(await platform.getQualification(created.value.id))}catch(error){ElMessage.error(error instanceof Error?error.message:'Could not load qualification')}finally{loading.value=false}}
async function startQualification(){if(!created.value?.id||enrollmentBlocked.value)return;loading.value=true;try{applyQualification(await platform.startQualification(created.value.id));ElMessage.success('Persisted qualification run started')}catch(error){ElMessage.error(error instanceof Error?error.message:'Could not start qualification')}finally{loading.value=false}}
function openCheck(check:any){selectedCheck.value=check;checkStatus.value='passed';evidenceReference.value='';evidenceNotes.value='';checkDialog.value=true}
async function saveCheck(){if(!qualification.value||!selectedCheck.value||enrollmentBlocked.value)return;loading.value=true;try{applyQualification(await platform.recordQualificationCheck(qualification.value.id,selectedCheck.value.id,{status:checkStatus.value,evidence_reference:evidenceReference.value,notes:evidenceNotes.value||undefined}));checkDialog.value=false;ElMessage.success('Qualification evidence persisted')}catch(error){ElMessage.error(error instanceof Error?error.message:'Could not record check')}finally{loading.value=false}}
function openDecision(value:'approve'|'reject'){decision.value=value;decisionReason.value='';password.value='';decisionDialog.value=true}
async function submitDecision(){if(!qualification.value||enrollmentBlocked.value)return;loading.value=true;try{applyQualification(await platform.decideQualification(qualification.value.id,decision.value,decisionReason.value,password.value));decisionDialog.value=false;if(decision.value==='approve'){active.value=3;ElMessage.success('Device and SIM wallets approved')}else ElMessage.warning('Qualification rejected; SIM wallets remain pending')}catch(error){ElMessage.error(error instanceof Error?error.message:'Decision failed')}finally{loading.value=false}}
async function next(){if(active.value===0)return createRecord();if(active.value===1){active.value=2;await loadQualification();return}if(active.value===2){if(qualification.value?.status==='approved')active.value=3;else ElMessage.warning('Staff approval is required before completion')}}
function back(){if(active.value===1)return router.push('/fleet');active.value--}
</script>
<template><div class="page add-page"><div class="page-heading"><div><p class="eyebrow">Fleet enrollment</p><h1>{{resumedFromUrl?'Resume phone enrollment':'Add phone'}}</h1><span class="muted">Server-issued activation and audited dual-SIM qualification.</span></div><el-button @click="$router.push('/fleet')">Cancel</el-button></div>
<el-steps :active="active" finish-status="success" simple class="steps"><el-step title="Device record"/><el-step title="Install & activate"/><el-step title="SIM qualification"/><el-step title="Complete"/></el-steps>
<section v-if="active===0" class="panel wizard"><div class="panel-head"><div><h2>1. Create the server device record</h2><span class="muted small">The cloud creates the activation code after all enrolled SIM identities are recorded.</span></div><div class="toolbar"><el-button size="small" @click="openStructure('location')">New location</el-button><el-button size="small" @click="openStructure('group')">New group</el-button></div></div><el-alert v-if="platform.demoMode" title="Enrollment is unavailable in demo mode; no local activation code will be fabricated." type="warning" :closable="false" show-icon/><el-alert v-else-if="!groups.length" title="Create a fleet location and group before enrolling the first phone." type="info" :closable="false" show-icon/><div class="panel-body form-grid"><el-form-item label="Device name"><el-input v-model="form.name" placeholder="AA-Bole-04"/></el-form-item><el-form-item label="Fleet group"><el-select v-model="form.groupId" style="width:100%"><el-option v-for="group in groups" :key="group.id" :label="group.label" :value="group.id"/></el-select></el-form-item><el-form-item label="Model"><el-input v-model="form.model"/></el-form-item><div class="policy"><el-icon><Check/></el-icon><span><b>Production baseline</b><small>Stock signed firmware · Android 12+ · root and exposed ADB prohibited</small></span></div><article v-for="sim in form.sims" :key="sim.slot" class="sim-form"><header>SIM {{sim.slot+1}}</header><el-form-item label="ICCID"><el-input v-model="sim.iccid" placeholder="Full ICCID from the physical SIM"/></el-form-item><el-form-item label="Telebirr number"><el-input v-model="sim.phone_number" placeholder="09… or +2519…"/></el-form-item><el-form-item label="Registered Telebirr name"><el-input v-model="sim.account_name"/></el-form-item></article></div></section>
<section v-else-if="active===1" class="panel wizard"><div class="panel-head"><div><h2>2. Install and activate</h2><span class="muted small">Device {{created?.name}} · {{created?.id}}</span></div><el-radio-group v-model="language" size="small"><el-radio-button value="en">English</el-radio-button><el-radio-button value="zh">中文</el-radio-button></el-radio-group></div><div class="activation-grid panel-body"><div class="identity-card"><span>Enrollment record</span><strong>{{created?.name}}</strong><code>{{created?.id}}</code><div><small v-for="sim in created?.sims??[]" :key="sim.id??sim.slot">SIM {{sim.slot+1}} · {{sim.phone_number}} · {{sim.account_name}}</small></div></div><div class="activation"><template v-if="code"><span>One-time activation code</span><strong>{{code}}</strong><small>Expires {{expires}}</small><div class="toolbar"><el-button :icon="CopyDocument" @click="copy">Copy</el-button><el-button :icon="Refresh" :loading="loading" @click="regenerate">Replace with a fresh code</el-button></div></template><template v-else><el-alert title="The previous activation code cannot be recovered after a refresh." type="warning" :closable="false" show-icon/><p v-if="canRegenerate">This device is still pending. Generate a fresh one-time code; the server will invalidate any older unused code.</p><p v-else>The agent has already activated or the device moved beyond the pending state. Continue to qualification; do not create another credential.</p><el-button v-if="canRegenerate" type="primary" :icon="Refresh" :loading="loading" @click="regenerate">Generate fresh activation code</el-button></template><p>On the phone, open Telebirr Device Agent and type the displayed code into <b>One-time activation code</b>. Codes are hashed in the database and never recoverable later.</p></div><div class="manual-card"><span>Give this PDF to the local installer</span><strong>{{language==='en'?'Simple phone setup guide · English':'简单手机安装指南 · 简体中文'}}</strong><p>{{language==='en'?'Only direct click-by-click instructions for AirDroid, OpenClaw, the Agent and both SIMs.':'只有 AirDroid、OpenClaw、设备代理和双卡的直接逐步点击说明。'}}</p><div class="toolbar"><el-button tag="a" :href="fieldManualUrl" target="_blank" :icon="Printer">Open simple guide</el-button><el-button tag="a" :href="fieldManualUrl" :download="language==='en'?'telebirr-field-phone-installation-en.pdf':'telebirr-field-phone-installation-zh-CN.pdf'" :icon="Download">Download PDF</el-button><el-button tag="a" :href="operatorManualUrl" target="_blank" text>Technical operator manual</el-button></div></div></div></section>
<section v-else-if="active===2" class="panel wizard"><div class="panel-head"><div><h2>3. Persist and approve qualification</h2><span class="muted small">Device {{created?.name}} · {{created?.id}}</span></div><div class="toolbar"><el-button :icon="Refresh" :loading="loading" @click="loadQualification">Refresh</el-button><el-button type="primary" :disabled="enrollmentBlocked" @click="startQualification">Start / resume run</el-button></div></div><div class="panel-body"><el-alert v-if="enrollmentBlocked" title="Enrollment is blocked for this device. Use Recover / re-enroll from Fleet before continuing." type="error" :closable="false" show-icon/><el-alert v-else-if="qualification" :title="`Device ${qualification.device.status} · run ${qualification.status} · Agent ${qualification.device.agent_version??'not connected'}`" :type="qualification.status==='approved'?'success':qualification.status==='failed'?'error':'warning'" :closable="false" show-icon/><el-empty v-else description="Load or start the qualification run"/><template v-if="qualification"><div class="device-checks"><span>Heartbeat</span><b>{{qualification.device.last_heartbeat_at?new Date(qualification.device.last_heartbeat_at).toLocaleString():'Not received'}}</b><span>Permissions</span><b>{{qualification.device.permissions_ok?'OK':'Pending'}}</b><span>Accessibility</span><b>{{qualification.device.accessibility_ok?'OK':'Pending'}}</b><span>OpenClaw</span><b>{{qualification.device.openclaw_paired?'Paired':'Pending'}}</b></div><div class="qualification"><article v-for="sim in [null,...qualification.device.sims]" :key="sim?.id??'device'"><header><strong>{{sim?`SIM ${sim.slot+1}`:'Handset checks'}}</strong><el-tag :type="qualification.status==='approved'?'success':'warning'">{{sim?.status??qualification.device.status}}</el-tag></header><ul><li v-for="check in qualification.checks.filter((item:any)=>sim?item.sim_wallet_id===sim.id:item.sim_wallet_id===null)" :key="check.id"><span :class="check.status"/><div><b>{{check.key.replace(/_/g,' ')}}</b><small>{{check.status}}<template v-if="check.evidence"> · {{check.evidence.reference??check.evidence.source}}</template></small></div><el-button size="small" :disabled="enrollmentBlocked||qualification.status==='approved'" @click="openCheck(check)">Record</el-button></li></ul></article></div><div class="approval"><el-alert title="Approval is a financial safety boundary. It activates every enrolled SIM for assignment." type="warning" :closable="false" show-icon/><div><el-button type="danger" plain :disabled="enrollmentBlocked||qualification.status==='approved'" @click="openDecision('reject')">Reject run</el-button><el-button type="primary" :disabled="enrollmentBlocked||!allPassed||qualification.status==='approved'" @click="openDecision('approve')">Approve with password</el-button></div></div></template></div></section>
<section v-else class="panel wizard complete"><div class="done"><el-icon><Check/></el-icon></div><h2>{{form.name}} is approved</h2><p>The persisted run is approved and both SIM wallets are eligible only while device health remains valid.</p><el-button type="primary" @click="$router.push('/fleet')">Open fleet</el-button></section>
<div v-if="active<3" class="wizard-actions"><el-button :disabled="active===0" @click="back">Back</el-button><el-button type="primary" :disabled="enrollmentBlocked" :loading="loading" @click="next">{{active===0?'Create server record':active===2?'Complete enrollment':'Continue'}}</el-button></div>
<el-dialog v-model="checkDialog" title="Record qualification evidence" width="min(520px,92vw)"><el-form label-position="top"><el-form-item label="Outcome"><el-radio-group v-model="checkStatus"><el-radio-button value="passed">Passed</el-radio-button><el-radio-button value="failed">Failed</el-radio-button></el-radio-group></el-form-item><el-form-item label="Evidence reference"><el-input v-model="evidenceReference" placeholder="Test ticket, receipt, screenshot object key, or provider transaction ID"/></el-form-item><el-form-item label="Notes"><el-input v-model="evidenceNotes" type="textarea" :rows="3"/></el-form-item></el-form><template #footer><el-button @click="checkDialog=false">Cancel</el-button><el-button type="primary" :loading="loading" @click="saveCheck">Persist evidence</el-button></template></el-dialog>
<el-dialog v-model="decisionDialog" :title="decision==='approve'?'Approve device qualification':'Reject device qualification'" width="min(520px,92vw)"><el-alert :title="decision==='approve'?'This activates the enrolled SIM wallets.':'The SIM wallets will remain pending.'" :type="decision==='approve'?'warning':'error'" :closable="false" show-icon/><el-form label-position="top" style="margin-top:16px"><el-form-item label="Decision reason"><el-input v-model="decisionReason" type="textarea" :rows="3"/></el-form-item><el-form-item label="Your password"><el-input v-model="password" type="password" show-password autocomplete="current-password"/></el-form-item></el-form><template #footer><el-button @click="decisionDialog=false">Cancel</el-button><el-button :type="decision==='approve'?'primary':'danger'" :loading="loading" @click="submitDecision">Confirm decision</el-button></template></el-dialog>
<el-dialog v-model="structureDialog" :title="structureMode==='location'?'Create fleet location':'Create fleet group'" width="min(500px,92vw)"><el-form label-position="top"><el-form-item v-if="structureMode==='group'" label="Location"><el-select v-model="structure.locationId" style="width:100%"><el-option v-for="location in locations" :key="location.id" :label="location.label" :value="location.id"/></el-select></el-form-item><el-form-item label="Code"><el-input v-model="structure.code" maxlength="40" placeholder="AA-BOLE"/></el-form-item><el-form-item label="Display name"><el-input v-model="structure.name" maxlength="120" placeholder="Addis Ababa · Bole"/></el-form-item></el-form><template #footer><el-button @click="structureDialog=false">Cancel</el-button><el-button type="primary" :loading="loading" @click="saveStructure">Create</el-button></template></el-dialog>
</div></template>
<style scoped>.add-page{max-width:1050px}.steps{margin-bottom:18px;border:1px solid var(--line);background:#fff}.wizard{min-height:410px}.form-grid{display:grid;grid-template-columns:1fr 1fr;gap:6px 20px}.policy{grid-column:1/-1;display:flex;gap:10px;padding:13px;background:#eaf8f4;color:#087d69;border-radius:9px}.policy b,.policy small{display:block}.policy small{font-size:10px;margin-top:3px}.sim-form{border:1px solid var(--line);border-radius:12px;padding:15px}.sim-form header{font-weight:800;color:var(--primary);margin-bottom:12px}.wizard-actions{display:flex;justify-content:flex-end;gap:8px;margin-top:16px}.activation-grid{display:grid;grid-template-columns:1fr;gap:20px}.identity-card,.activation{padding:22px;background:#f7f8fb;border-radius:12px}.identity-card>span,.identity-card>strong,.identity-card>code,.identity-card small,.activation>span,.activation>strong,.activation>small{display:block}.identity-card>span,.activation>span,.manual-card>span{font-size:10px;color:var(--muted);text-transform:uppercase;font-weight:700}.identity-card>strong{font-size:16px;margin:7px 0 3px}.identity-card>code{font-size:10px;color:var(--muted);margin-bottom:12px}.identity-card small{font-size:10px;margin-top:5px}.activation>strong{font:800 30px 'Manrope';letter-spacing:.12em;margin:9px 0}.activation>small{font-size:10px;color:var(--muted);margin:-4px 0 12px}.activation p,.manual-card p{font-size:11px;color:var(--muted);line-height:1.6}.manual-card{padding:18px;background:#f6f6ff;border-radius:11px}.manual-card strong{display:block;margin-top:7px}.device-checks{display:grid;grid-template-columns:repeat(4,auto 1fr);gap:8px 12px;background:#f7f8fb;border-radius:10px;padding:12px;margin:15px 0}.device-checks span{color:var(--muted);font-size:10px}.device-checks b{font-size:10px}.qualification{display:grid;grid-template-columns:repeat(3,1fr);gap:12px}.qualification article{padding:15px;border:1px solid var(--line);border-radius:11px}.qualification header{display:flex;justify-content:space-between;margin-bottom:12px}.qualification ul{list-style:none;padding:0;margin:0}.qualification li{display:grid;grid-template-columns:8px 1fr auto;gap:8px;align-items:center;padding:9px 0;border-top:1px solid var(--line)}.qualification li>span{width:8px;height:8px;border-radius:50%;background:#d5d9e2}.qualification li>span.passed{background:var(--teal)}.qualification li>span.failed{background:var(--danger)}.qualification li b,.qualification li small{display:block}.qualification li b{font-size:10px;text-transform:capitalize}.qualification li small{font-size:9px;color:var(--muted);margin-top:2px}.approval{display:flex;justify-content:space-between;gap:15px;align-items:center;margin-top:17px}.approval .el-alert{flex:1}.complete{text-align:center;padding:70px 20px}.done{width:58px;height:58px;border-radius:50%;display:grid;place-items:center;background:#e7f7f3;color:var(--teal);font-size:28px;margin:0 auto 15px}.complete p{color:var(--muted);font-size:12px;margin-bottom:20px}@media(max-width:850px){.qualification{grid-template-columns:1fr}.device-checks{grid-template-columns:auto 1fr}.form-grid{grid-template-columns:1fr}.policy{grid-column:auto}.approval{align-items:stretch;flex-direction:column}}</style>
